#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        double H, S;
        scanf("%lf %lf", &H, &S);
        double base = sqrt((2 * S) / (H + sqrt(H * H - (4 * S) / H)));
        double height = (2 * S) / base;
        if (base <= 0 || height <= 0 || base * base + height * height != H * H) {
            printf("-1\n");
        } else {
            printf("%.5f %.5f %.5f\n", base, height, H);
        }
    }
    return 0;
}

