import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            double H = sc.nextDouble();
            double S = sc.nextDouble();
            double base = Math.sqrt((2 * S) / (H + Math.sqrt(H * H - (4 * S) / H)));
            double height = (2 * S) / base;
            if (base <= 0 || height <= 0 || base * base + height * height != H * H) {
                System.out.println(-1);
            } else {
                System.out.printf("%.5f %.5f %.5f\n", base, height, H);
            }
        }
    }
}

