const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [H, S] = readline().split(' ').map(Number);
    const base = Math.sqrt((2 * S) / (H + Math.sqrt(H * H - (4 * S) / H)));
    const height = (2 * S) / base;
    if (base <= 0 || height <= 0 || base * base + height * height != H * H) {
        console.log(-1);
    } else {
        console.log(base.toFixed(5), height.toFixed(5), H.toFixed(5));
    }
}

